function candidate(location) {
  if (typeof location !== "string") {
    throw new TypeError("Path must be a string");
  }

  if (location.length === 0) {
    return ".";
  }

  const startsAtRoot = location.charCodeAt(0) === 47;
  let cut = -1;
  let skippingSeparators = true;

  for (let index = location.length - 1; index >= 1; index -= 1) {
    if (location.charCodeAt(index) === 47) {
      if (!skippingSeparators) {
        cut = index;
        break;
      }
    } else {
      skippingSeparators = false;
    }
  }

  if (cut === -1) {
    return startsAtRoot ? "/" : ".";
  }

  if (startsAtRoot && cut === 1) {
    return "//";
  }

  return location.slice(0, cut);
}
